const p1 = fetch('/api/users').then(r => r.json());
const p2 = fetch('/api/posts').then(r => r.json());
const p3 = fetch('/api/comments').then(r => r.json());

// All three requests are 'in flight' at the same time.
Promise.all([p1, p2, p3])
  .then(([users, posts, comments]) => {
    // This array matches the order of the inputs exactly.
    console.log('All data loaded!');
    renderPage(users, posts, comments);
  })
  .catch(error => {
    // If ANY of the three endpoints 404s or fails, we end up here instantly.
    console.error('Failed to load page data:', error);
  });
